properties.query:
let DisabledParsers=materialize(_GetWatchlist('ASimDisabledParsers') | where SearchKey in ('Any', 'ExcludeimAgentEvent') | extend SourceSpecificParser=column_ifexists('SourceSpecificParser','') | distinct SourceSpecificParser | where isnotempty(SourceSpecificParser));
let vimBuiltInDisabled=toscalar('ExcludevimAgentEvent' in (DisabledParsers) or 'Any' in (DisabledParsers)); 
let parser=(
  starttime: datetime=datetime(null), 
  endtime: datetime=datetime(null), 
  agentid_has_any: dynamic=dynamic([]),
  agentname_has_any: dynamic=dynamic([]),
  username_has_any: dynamic=dynamic([]),
  pack:bool=false)
{
union isfuzzy=true
  vimAgentEventEmpty
};
parser (starttime=starttime, endtime=endtime, agentid_has_any=agentid_has_any, agentname_has_any=agentname_has_any, username_has_any=username_has_any, pack=pack)
